type AnyRecord = Record<string, any>;
type Field = { name: string; label: string; type?: 'text' | 'email' | 'password' | 'number' | 'textarea' | 'select' | 'checkbox' | 'relation' | 'relation-multi'; placeholder?: string; required?: boolean; options?: string[]; relationEndpoint?: string; relationLabel?: (item: AnyRecord) => string };

const titles: Record<string, [string, string]> = {
  users: ['Users', 'Manage accounts, status, profiles, and access assignments.'], admins: ['Admins & roles', 'Control staff access with explicit role assignments.'], 'media-assets': ['Media assets', 'Review provider metadata without exposing storage locators.'], groups: ['Groups & access', 'Organize subscribers, manage members, and grant episode access in bulk.'], subscriptions: ['Subscriptions', 'Review manual payments and maintain subscriber access.'], notifications: ['Notifications', 'Publish broadcasts and send them through Firebase.'], messages: ['Messages', 'Read the operational inbox and communicate with users.'], banners: ['Banner management', 'Keep the mobile home screen current.'], trending: ['Trending dramas', 'Curate the order shown to viewers.'], analytics: ['Analytics & reports', 'Understand views, users, and the operational pulse.'], comments: ['Comments', 'Moderate discussion around episodes and groups.'], security: ['Security incidents', 'Investigate client-reported security events and blocks.'], releases: ['APK & versions', 'Publish app releases through the secure provider proxy.'], settings: ['Settings & remote config', 'Manage subscription instructions and mobile feature flags.'], audit: ['Audit logs', 'Trace sensitive staff and platform actions.'], uploads: ['Uploads', 'Upload media and release files through server-owned chunk sessions.'], firebase: ['Firebase delivery', 'Check Firebase configuration and send a controlled test notification.'], widevine: ['Widevine / DRM', 'Validate the configured license endpoint without exposing credentials.'], 'media-validation': ['Media validation', 'Check encrypted locators and provider allowlists before publishing.'], 'media-preview': ['Media preview', 'Review secure playback metadata for a selected media asset.'], utilities: ['Legacy utilities', 'Export safe operational records and import approved CSV datasets.'], content: ['Content library', 'Manage the catalog in the hierarchy staff already know: drama, season, then episode.'], 'content-dramas': ['Dramas', 'Create and maintain the top-level drama catalog.'], 'content-seasons': ['Seasons', 'Attach each season to a drama using a readable selector.'], 'content-episodes': ['Episodes', 'Attach each episode to a drama and season using dependent selectors.'],
};

const resources: Record<string, { endpoint: string; listEndpoint?: string; permission?: string; fields: Field[]; columns: (refresh: () => void) => ColumnDef<AnyRecord>[] }> = {
  users: { endpoint: '/users', fields: [{ name: 'username', label: 'Name', required: true }, { name: 'email', label: 'Email', type: 'email', required: true }, { name: 'password', label: 'Temporary password', type: 'password', required: true }, { name: 'profileImageKey', label: 'Profile image key' }], columns: () => [{ accessorKey: 'username', header: 'User', cell: ({ row }) => <div><div className="font-semibold">{row.original.username}</div><div className="text-xs text-slate-500">{row.original.email}</div></div> }, { accessorKey: 'status', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.status} /> }, { accessorKey: 'roles', header: 'Role', cell: ({ row }) => row.original.roles?.map((r: AnyRecord) => r.role.name).join(', ') ?? 'User' }, { accessorKey: 'createdAt', header: 'Joined', cell: ({ row }) => formatDate(row.original.createdAt) }, { id: 'actions', header: '', cell: ({ row }) => <UserStatusAction user={row.original} /> }] },
  admins: { endpoint: '/admins', fields: [{ name: 'username', label: 'Name', required: true }, { name: 'email', label: 'Email', type: 'email', required: true }, { name: 'password', label: 'Temporary password', type: 'password', required: true }, { name: 'role', label: 'Role', type: 'select', options: ['ADMIN', 'SUB_ADMIN', 'MODERATOR'], required: true }], columns: (refresh) => [{ accessorKey: 'username', header: 'Administrator', cell: ({ row }) => <div><div className="font-semibold">{row.original.username}</div><div className="text-xs text-slate-500">{row.original.email}</div></div> }, { accessorKey: 'status', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.status} /> }, { accessorKey: 'roles', header: 'Roles', cell: ({ row }) => <div className="flex flex-wrap gap-1">{row.original.roles?.map((r: AnyRecord) => <StatusBadge key={r.role.code} value={r.role.name} />)}</div> }, { accessorKey: 'createdAt', header: 'Joined', cell: ({ row }) => formatDate(row.original.createdAt) }, { id: 'actions', header: '', cell: ({ row }) => <AdminActions user={row.original} refresh={refresh} /> }] },
  'media-assets': { endpoint: '/media-assets', fields: [{ name: 'episodeId', label: 'Episode', type: 'relation', relationEndpoint: '/episodes', relationLabel: (item) => `Episode ${item.episodeNumber} · ${item.title ?? 'Untitled'}`, required: true }, { name: 'mediaType', label: 'Media type', type: 'select', options: ['MP4', 'HLS', 'DASH', 'OTHER'], required: true }, { name: 'provider', label: 'Provider', required: true }, { name: 'encryptedLocator', label: 'Encrypted locator', required: true }], columns: () => [{ accessorKey: 'episodeId', header: 'Episode', cell: ({ row }) => <span className="font-mono text-xs">{row.original.episodeId}</span> }, { accessorKey: 'mediaType', header: 'Type', cell: ({ row }) => <StatusBadge value={row.original.mediaType} /> }, { accessorKey: 'provider', header: 'Provider' }, { accessorKey: 'status', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.status} /> }, { accessorKey: 'version', header: 'Version' }, { accessorKey: 'updatedAt', header: 'Updated', cell: ({ row }) => formatDate(row.original.updatedAt) }] },
  groups: { endpoint: '/access/groups', fields: [{ name: 'name', label: 'Group name', required: true }], columns: (refresh) => [{ accessorKey: 'name', header: 'Group', cell: ({ row }) => <div><div className="font-semibold">{row.original.name}</div><div className="text-xs text-slate-500">{row.original.id}</div></div> }, { accessorKey: '_count', header: 'Members', cell: ({ row }) => formatNumber(row.original._count?.members) }, { accessorKey: '_count', header: 'Grants', cell: ({ row }) => formatNumber(row.original._count?.grants) }, { id: 'actions', header: '', cell: ({ row }) => <GroupActions id={row.original.id} refresh={refresh} /> }] },
  notifications: { endpoint: '/notifications', fields: [{ name: 'title', label: 'Title', required: true }, { name: 'message', label: 'Message', type: 'textarea', required: true }, { name: 'imageKey', label: 'Image key' }], columns: () => [{ accessorKey: 'title', header: 'Notification', cell: ({ row }) => <div><div className="font-semibold">{row.original.title}</div><div className="max-w-md truncate text-xs text-slate-500">{row.original.message}</div></div> }, { accessorKey: 'createdAt', header: 'Created', cell: ({ row }) => formatDate(row.original.createdAt) }] },
  banners: { endpoint: '/banners', listEndpoint: '/admin/banners', fields: [{ name: 'imageKey', label: 'Image key' }, { name: 'videoKey', label: 'Video key' }, { name: 'isActive', label: 'Active', type: 'checkbox' }], columns: () => [{ accessorKey: 'imageKey', header: 'Image', cell: ({ row }) => <span className="font-mono text-xs">{row.original.imageKey ?? 'No image'}</span> }, { accessorKey: 'videoKey', header: 'Video', cell: ({ row }) => <span className="font-mono text-xs">{row.original.videoKey ?? 'No video'}</span> }, { accessorKey: 'isActive', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.isActive} /> }, { accessorKey: 'createdAt', header: 'Created', cell: ({ row }) => formatDate(row.original.createdAt) }] },
  security: { endpoint: '/security/incidents', fields: [], columns: () => [{ accessorKey: 'incidentType', header: 'Incident', cell: ({ row }) => <div><div className="font-semibold">{row.original.incidentType}</div><div className="text-xs text-slate-500">{row.original.appArea ?? 'App-wide'}</div></div> }, { accessorKey: 'severity', header: 'Severity', cell: ({ row }) => <StatusBadge value={row.original.severity} /> }, { accessorKey: 'deviceModel', header: 'Device' }, { accessorKey: 'ipAddress', header: 'IP address' }, { accessorKey: 'createdAt', header: 'Reported', cell: ({ row }) => formatDate(row.original.createdAt) }] },
  releases: { endpoint: '/app/releases', fields: [{ name: 'versionName', label: 'Version name', required: true }, { name: 'versionCode', label: 'Version code', type: 'number', required: true }, { name: 'storageKey', label: 'Allowlisted provider URL', required: true }, { name: 'originalName', label: 'Original filename' }, { name: 'fileSize', label: 'File size (bytes)', type: 'number' }, { name: 'isActive', label: 'Active', type: 'checkbox' }], columns: () => [{ accessorKey: 'versionName', header: 'Release', cell: ({ row }) => <div><div className="font-semibold">{row.original.versionName}</div><div className="text-xs text-slate-500">Build {row.original.versionCode}</div></div> }, { accessorKey: 'originalName', header: 'File' }, { accessorKey: 'fileSize', header: 'Size', cell: ({ row }) => row.original.fileSize ? `${formatNumber(Number(row.original.fileSize) / 1024 / 1024)} MB` : 'Not set' }, { accessorKey: 'isActive', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.isActive} /> }, { accessorKey: 'createdAt', header: 'Uploaded', cell: ({ row }) => formatDate(row.original.createdAt) }] },
};

export function SectionPage({ section }: { section: string }) {
  if (section === 'content') return <ContentWorkspace />;
  if (section === 'admins') return <AdminsWorkspace />;
  if (section === 'groups') return <GroupsWorkspace />;
  if (section === 'subscriptions') return <SubscriptionsWorkspace />;
  if (section === 'settings') return <SettingsWorkspace />;
  if (section === 'analytics') return <AnalyticsWorkspace />;
  if (section === 'trending') return <TrendingWorkspace />;
  if (section === 'comments') return <CommentsWorkspace />;
  if (section === 'audit') return <AuditWorkspace />;
  if (section === 'messages') return <MessagesWorkspace />;
  if (section === 'uploads') return <UploadsWorkspace />;
  if (section === 'firebase') return <FirebaseWorkspace />;
  if (section === 'widevine') return <WidevineWorkspace />;
  if (section === 'media-validation' || section === 'media-preview') return <MediaValidationWorkspace previewOnly={section === 'media-preview'} />;
  if (section === 'utilities') return <UtilitiesWorkspace />;
  const resource = resources[section] ?? resources.users;
  return <ResourceWorkspace section={section} resource={resource} />;
}

type FormRendererProps = { editing: AnyRecord | null; onCancel: () => void; onSubmit: (payload: AnyRecord) => void; submitting: boolean };
type FormRenderer = (props: FormRendererProps) => ReactNode;

function ResourceWorkspace({ section, resource, formRenderer }: { section: string; resource: typeof resources[string]; formRenderer?: FormRenderer }) {
  const queryClient = useQueryClient();
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [formOpen, setFormOpen] = useState(false);
  const [editing, setEditing] = useState<AnyRecord | null>(null);
  const [notice, setNotice] = useState('');
  const query = useQuery({ queryKey: [section, page, search], queryFn: async () => (await api.get<PageResult<AnyRecord>>(resource.listEndpoint ?? resource.endpoint, { params: { page, limit: 15, search: search || undefined } })).data });
  const title = titles[section] ?? titles.users;
  const mutation = useMutation({ mutationFn: (payload: AnyRecord) => { if (!editing) { if (section === 'users') { const { username, email, password } = payload; return api.post(resource.endpoint, { username, email, password }); } return api.post(resource.endpoint, payload); } if (section === 'users') { const { username, email, profileImageKey } = payload; return api.patch(`${resource.endpoint}/${editing.id}/profile`, { username, email, profileImageKey: profileImageKey || undefined }); } if (section === 'roles') { const { name, description } = payload; return api.patch(`${resource.endpoint}/${editing.id}`, { name, description }); } if (section === 'permissions') { return api.patch(`${resource.endpoint}/${editing.id}`, { description: payload.description }); } return api.patch(`${resource.endpoint}/${editing.id}`, payload); }, onSuccess: () => { setFormOpen(false); setEditing(null); setNotice(editing ? 'Record updated successfully.' : 'Record created successfully.'); void queryClient.invalidateQueries({ queryKey: [section] }); }, onError: (error) => setNotice(apiError(error)) });
  const baseColumns = useMemo(() => resource.columns(() => void queryClient.invalidateQueries({ queryKey: [section] })), [resource, queryClient, section]);
  const canDelete = ['users', 'roles', 'banners', 'notifications', 'media-assets', 'releases', 'trending', 'content-dramas', 'content-seasons', 'content-episodes'].includes(section);
  const columns = useMemo(() => { const needsResourceActions = section === 'users' || section === 'roles' || (!baseColumns.some((column) => column.id === 'actions') && (resource.fields.length > 0 || canDelete)); if (!needsResourceActions) return baseColumns; return [...baseColumns, { id: 'manage', header: 'Actions', cell: ({ row }: { row: { original: AnyRecord } }) => <ResourceActions endpoint={resource.endpoint} id={row.original.id} canEdit={resource.fields.length > 0} canDelete={canDelete} canSend={section === 'notifications'} onEdit={() => { setEditing(row.original); setFormOpen(true); }} onDeleted={() => void queryClient.invalidateQueries({ queryKey: [section] })} /> }]; }, [baseColumns, canDelete, queryClient, resource.endpoint, resource.fields.length, section]);
  const closeForm = () => { setFormOpen(false); setEditing(null); };
  return <div><PageHeader eyebrow="Operations" title={title[0]} description={title[1]} actions={resource.fields.length ? <button className="btn-primary" onClick={() => { setEditing(null); setFormOpen(true); }}><Plus size={16} /> Add new</button> : <button className="btn-secondary" onClick={() => query.refetch()}><RefreshCw size={16} /> Refresh</button>} />{formOpen && (formRenderer ? formRenderer({ editing, onCancel: closeForm, onSubmit: (payload) => mutation.mutate(payload), submitting: mutation.isPending }) : <FormPanel key={editing?.id ?? 'new'} title={`${editing ? 'Edit' : 'Add'} ${title[0].replace(/s$/, '')}`} fields={resource.fields} initialValues={editing ?? undefined} onCancel={closeForm} onSubmit={(payload) => mutation.mutate(payload)} submitting={mutation.isPending} />)}{notice && <Toast message={notice} kind={notice.includes('successfully') ? 'success' : 'error'} />}{section !== 'security' && <div className="mb-4 flex max-w-xl items-center gap-2"><div className="relative flex-1"><Search className="absolute left-3 top-2.5 text-slate-400" size={16} /><input className="input pl-9" value={search} onChange={(e) => { setPage(1); setSearch(e.target.value); }} placeholder={`Search ${title[0].toLowerCase()}`} /></div><button className="btn-secondary" onClick={() => query.refetch()} aria-label="Refresh list"><RefreshCw size={16} /></button></div>}{query.isLoading ? <LoadingState /> : query.isError ? <ErrorState message={apiError(query.error)} onRetry={() => query.refetch()} /> : <DataTable data={query.data?.items ?? (Array.isArray(query.data) ? query.data : [])} columns={columns} page={query.data?.page} totalPages={query.data?.totalPages} onPageChange={setPage} />}</div>;
}

function FormPanel({ title, fields, initialValues, onCancel, onSubmit, submitting }: { title: string; fields: Field[]; initialValues?: AnyRecord; onCancel: () => void; onSubmit: (payload: AnyRecord) => void; submitting?: boolean }) {
  const [values, setValues] = useState<AnyRecord>(() => Object.fromEntries(fields.map((field) => [field.name, initialValues?.[field.name] ?? (field.type === 'checkbox' ? false : field.type === 'relation-multi' ? [] : '')])));
  const [formError, setFormError] = useState('');
  function change(field: Field, value: string | boolean | string[]) { setValues((current) => ({ ...current, [field.name]: field.type === 'number' ? Number(value) : value })); }
  function submit() { const missing = fields.find((field) => field.required && (values[field.name] === undefined || values[field.name] === null || String(values[field.name]).trim() === '')); if (missing) { setFormError(`${missing.label} is required.`); return; } setFormError(''); onSubmit(values); }
  return <section className="surface mb-6 p-6"><div className="flex items-center justify-between"><div><div className="eyebrow">Secure form</div><h3 className="mt-1 text-lg font-bold">{title}</h3></div><button className="btn-quiet h-8 w-8 p-0" onClick={onCancel} aria-label="Close form"><X size={16} /></button></div><div className="mt-5 grid gap-4 md:grid-cols-2">{fields.map((field) => <label key={field.name} className={field.type === 'textarea' || field.type === 'relation-multi' ? 'md:col-span-2' : ''}><span className="mb-2 block text-sm font-semibold">{field.label}{field.required && <span className="text-brand"> *</span>}</span>{field.type === 'textarea' ? <textarea className="input min-h-28 py-2" value={values[field.name]} onChange={(e) => change(field, e.target.value)} placeholder={field.placeholder} /> : field.type === 'select' ? <select className="select" value={values[field.name]} onChange={(e) => change(field, e.target.value)}><option value="">Select one</option>{field.options?.map((option) => <option key={option} value={option}>{option}</option>)}</select> : field.type === 'relation' ? <RelationshipSelect field={field} value={values[field.name] ?? ''} onChange={(value) => change(field, value)} /> : field.type === 'relation-multi' ? <RelationshipMultiSelect field={field} value={values[field.name] ?? []} onChange={(value) => change(field, value)} /> : field.type === 'checkbox' ? <div className="flex h-10 items-center gap-2"><input type="checkbox" checked={values[field.name]} onChange={(e) => change(field, e.target.checked)} className="h-4 w-4 accent-teal" /><span className="text-sm text-slate-500">Enabled</span></div> : <input className="input" type={field.type ?? 'text'} value={values[field.name]} onChange={(e) => change(field, e.target.value)} placeholder={field.placeholder} />}</label>)}</div>{formError && <div className="mt-4 border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">{formError}</div>}<div className="mt-6 flex justify-end gap-2"><button className="btn-secondary" onClick={onCancel}>Cancel</button><button className="btn-primary" disabled={submitting} onClick={submit}><Check size={15} />{submitting ? 'Saving...' : 'Save record'}</button></div></section>;
}

function relationItems(data: AnyRecord | AnyRecord[] | undefined): AnyRecord[] { return Array.isArray(data) ? data : data?.items ?? []; }
function RelationshipSelect({ field, value, onChange }: { field: Field; value: string; onChange: (value: string) => void }) {
  const [search, setSearch] = useState('');
  const list = useQuery({ queryKey: ['relationship-options', field.relationEndpoint, search], queryFn: async () => (await api.get(field.relationEndpoint!, { params: { page: 1, limit: 100, search: search || undefined } })).data });
  const selected = useQuery({ queryKey: ['relationship-selected', field.relationEndpoint, value], queryFn: async () => (await api.get(`${field.relationEndpoint}/${value}`)).data, enabled: Boolean(value) });
  const items = relationItems(list.data);
  const selectedItem = items.find((item) => item.id === value) ?? (selected.data?.id === value ? selected.data : null);
  const label = field.relationLabel ?? ((item: AnyRecord) => item.name ?? item.username ?? item.title ?? item.id);
  return <div className="space-y-2"><input className="input" value={search} onChange={(event) => setSearch(event.target.value)} placeholder={`Search ${field.label.toLowerCase()}...`} /><select className="select" value={value} onChange={(event) => onChange(event.target.value)}><option value="">Select {field.label.toLowerCase()}</option>{selectedItem && !items.some((item) => item.id === selectedItem.id) && <option value={selectedItem.id}>{label(selectedItem)}</option>}{items.map((item) => <option key={item.id} value={item.id}>{label(item)}</option>)}</select></div>;
}

function RelationshipMultiSelect({ field, value, onChange }: { field: Field; value: string[]; onChange: (value: string[]) => void }) {
  const [search, setSearch] = useState('');
  const list = useQuery({ queryKey: ['relationship-multi-options', field.relationEndpoint, search], queryFn: async () => (await api.get(field.relationEndpoint!, { params: { page: 1, limit: 100, search: search || undefined } })).data });
  const items = relationItems(list.data);
  const label = field.relationLabel ?? ((item: AnyRecord) => item.name ?? item.username ?? item.title ?? item.id);
  function toggle(id: string) { onChange(value.includes(id) ? value.filter((item) => item !== id) : [...value, id]); }
  return <div className="space-y-3 border border-line bg-slate-50 p-3"><input className="input" value={search} onChange={(event) => setSearch(event.target.value)} placeholder="Search episodes to add..." /><div className="grid max-h-48 gap-2 overflow-y-auto sm:grid-cols-2">{items.slice(0, 24).map((item) => <label key={item.id} className="flex cursor-pointer items-center gap-2 border border-line bg-white px-3 py-2 text-sm"><input type="checkbox" checked={value.includes(item.id)} onChange={() => toggle(item.id)} className="h-4 w-4 accent-teal" /><span className="truncate">{label(item)}</span></label>)}</div>{value.length > 0 && <div className="text-xs font-semibold text-slate-500">{value.length} episode{value.length === 1 ? '' : 's'} selected</div>}</div>;
}

function ResourceActions({ endpoint, id, canEdit, canDelete, canSend, onEdit, onDeleted }: { endpoint: string; id: string; canEdit: boolean; canDelete: boolean; canSend?: boolean; onEdit: () => void; onDeleted: () => void }) {
  const mutation = useMutation({ mutationFn: () => api.delete(`${endpoint}/${id}`), onSuccess: onDeleted });
  const send = useMutation({ mutationFn: () => api.post(`/notifications/${id}/send`) });
  return <div className="flex gap-1">{canEdit && <button className="btn-quiet h-8 px-2" onClick={onEdit}><Edit3 size={14} /> Edit</button>}{canSend && <button className="btn-quiet h-8 px-2 text-teal" disabled={send.isPending} onClick={() => send.mutate()}><Send size={14} /> Send</button>}{canDelete && <button className="btn-quiet h-8 px-2 text-red-600" disabled={mutation.isPending} onClick={() => { if (window.confirm('Delete this record?')) mutation.mutate(); }}><Trash2 size={14} /> Delete</button>}</div>;
}

function AdminsWorkspace() { const [tab, setTab] = useState<'admins' | 'roles' | 'permissions'>('admins'); return <div><PageHeader eyebrow="Identity and access" title="Admins & roles" description="Manage administrators, role definitions, and permission definitions from the secured control plane." actions={<div className="flex gap-1 border border-line bg-white p-1">{(['admins', 'roles', 'permissions'] as const).map((item) => <button key={item} onClick={() => setTab(item)} className={`px-3 py-2 text-xs font-semibold capitalize ${tab === item ? 'bg-ink text-white' : 'text-slate-500'}`}>{item}</button>)}</div>} />{tab === 'admins' ? <ResourceWorkspace section="admins" resource={resources.admins} /> : tab === 'roles' ? <ResourceWorkspace section="roles" resource={{ endpoint: '/rbac/roles', fields: [{ name: 'code', label: 'Role code', type: 'select', options: ['SUPER_ADMIN', 'ADMIN', 'SUB_ADMIN', 'MODERATOR', 'USER'], required: true }, { name: 'name', label: 'Role name', required: true }, { name: 'description', label: 'Description', type: 'textarea' }], columns: () => [{ accessorKey: 'code', header: 'Code', cell: ({ row }) => <StatusBadge value={row.original.code} /> }, { accessorKey: 'name', header: 'Name' }, { accessorKey: 'description', header: 'Description' }, { accessorKey: 'permissions', header: 'Permissions', cell: ({ row }) => formatNumber(row.original.permissions?.length) }, { id: 'actions', header: 'Actions', cell: ({ row }) => <RoleActions role={row.original} /> }] }} /> : <ResourceWorkspace section="permissions" resource={{ endpoint: '/rbac/permissions', fields: [{ name: 'code', label: 'Permission code', required: true }, { name: 'description', label: 'Description', type: 'textarea' }], columns: () => [{ accessorKey: 'code', header: 'Code', cell: ({ row }) => <span className="font-mono text-xs">{row.original.code}</span> }, { accessorKey: 'description', header: 'Description' }, { accessorKey: 'createdAt', header: 'Created', cell: ({ row }) => formatDate(row.original.createdAt) }] }} />}</div>; }
function RoleActions({ role }: { role: AnyRecord }) { const permissions = useQuery({ queryKey: ['permissions-for-role', role.id], queryFn: async () => (await api.get('/rbac/permissions')).data }); const [permissionId, setPermissionId] = useState(''); const client = useQueryClient(); const assign = useMutation({ mutationFn: () => api.post(`/rbac/roles/${role.id}/permissions`, { permissionId }), onSuccess: () => { setPermissionId(''); void client.invalidateQueries({ queryKey: ['roles'] }); } }); const remove = useMutation({ mutationFn: (id: string) => api.delete(`/rbac/roles/${role.id}/permissions/${id}`), onSuccess: () => void client.invalidateQueries({ queryKey: ['roles'] }) }); return <div className="flex flex-wrap items-center gap-1"><select className="select h-8 w-44 py-1 text-xs" value={permissionId} onChange={(event) => setPermissionId(event.target.value)} aria-label="Permission to assign"><option value="">Assign permission</option>{(permissions.data ?? []).map((permission: AnyRecord) => <option key={permission.id} value={permission.id}>{permission.code}</option>)}</select><button className="btn-quiet h-8 px-2 text-teal" disabled={!permissionId || assign.isPending} onClick={() => assign.mutate()}><UserPlus size={14} /> Assign</button>{(role.permissions ?? []).slice(0, 2).map((item: AnyRecord) => <button key={item.permission.id} className="btn-quiet h-8 px-2 text-red-600" onClick={() => remove.mutate(item.permission.id)} title={`Remove ${item.permission.code}`}><X size={14} /> {item.permission.code}</button>)}</div>; }

function UserStatusAction({ user }: { user: AnyRecord }) { const client = useQueryClient(); const next = user.status === 'ACTIVE' ? 'DISABLED' : 'ACTIVE'; const mutation = useMutation({ mutationFn: () => api.patch(`/users/${user.id}/status`, { status: next }), onSuccess: () => void client.invalidateQueries({ queryKey: ['users'] }) }); return <button className="btn-quiet h-8 px-2" disabled={mutation.isPending} onClick={() => mutation.mutate()}>{next === 'ACTIVE' ? <UserPlus size={14} /> : <Trash2 size={14} />}{next === 'ACTIVE' ? 'Activate' : 'Suspend'}</button>; }
function AdminActions({ user, refresh }: { user: AnyRecord; refresh: () => void }) { const [role, setRole] = useState('ADMIN'); const assign = useMutation({ mutationFn: () => api.post(`/admins/${user.id}/roles`, { role }), onSuccess: refresh }); const remove = useMutation({ mutationFn: () => api.delete(`/admins/${user.id}/roles`, { data: { role } }), onSuccess: refresh }); const removeUser = useMutation({ mutationFn: () => api.delete(`/users/${user.id}`), onSuccess: refresh }); return <div className="flex flex-wrap items-center gap-1"><select className="select h-8 w-28 py-1 text-xs" value={role} onChange={(event) => setRole(event.target.value)} aria-label="Administrative role"><option>ADMIN</option><option>SUB_ADMIN</option><option>MODERATOR</option></select><button className="btn-quiet h-8 px-2 text-teal" disabled={assign.isPending} onClick={() => assign.mutate()}><UserPlus size={14} /> Assign</button><button className="btn-quiet h-8 px-2" disabled={remove.isPending} onClick={() => remove.mutate()}><X size={14} /> Remove role</button><button className="btn-quiet h-8 px-2 text-red-600" disabled={removeUser.isPending} onClick={() => { if (window.confirm('Delete this administrator?')) removeUser.mutate(); }}><Trash2 size={14} /> Delete</button></div>; }
function GroupActions({ id, refresh }: { id: string; refresh: () => void }) { const mutation = useMutation({ mutationFn: () => api.delete(`/access/groups/${id}`), onSuccess: refresh }); return <button className="btn-quiet h-8 px-2 text-red-600" onClick={() => { if (window.confirm('Delete this group?')) mutation.mutate(); }}><Trash2 size={14} /> Delete</button>; }

function GroupsWorkspace() {
  const [tab, setTab] = useState<'groups' | 'members' | 'access' | 'direct'>('groups');
  const [notice, setNotice] = useState('');
  const [values, setValues] = useState<AnyRecord>({ subscription: true });
  const client = useQueryClient();
  const membersQuery = useQuery({ queryKey: ['group-members', values.groupId], queryFn: async () => (await api.get(`/access/groups/${values.groupId}/members`, { params: { page: 1, limit: 50 } })).data, enabled: tab === 'members' && String(values.groupId ?? '').length > 10 });
  const mutation = useMutation({ mutationFn: async (payload: AnyRecord) => { const episodeIds = String(payload.episodeIds ?? '').split(',').map((value) => value.trim()).filter(Boolean); if (tab === 'members') return api.post(`/access/groups/${payload.groupId}/members`, { userId: payload.userId, startsAt: payload.startsAt, endsAt: payload.endsAt, subscription: payload.subscription, comment: payload.comment }); if (tab === 'direct') return api.post('/access/grants/direct/bulk', { userId: payload.userId, episodeIds, startsAt: payload.startsAt, endsAt: payload.endsAt, note: payload.note }); return api.post('/access/grants/group/bulk', { groupId: payload.groupId, episodeIds, startsAt: payload.startsAt, endsAt: payload.endsAt, note: payload.note }); }, onSuccess: () => { setNotice(tab === 'members' ? 'Member access updated.' : 'Episode access granted.'); void client.invalidateQueries({ queryKey: ['groups'] }); void membersQuery.refetch(); }, onError: (error) => setNotice(apiError(error)) });
  const removeMember = useMutation({ mutationFn: ({ groupId, userId }: { groupId: string; userId: string }) => api.delete(`/access/groups/${groupId}/members/${userId}`), onSuccess: () => membersQuery.refetch(), onError: (error) => setNotice(apiError(error)) });
  const userField: Field = { name: 'userId', label: 'User', type: 'relation', relationEndpoint: '/users', relationLabel: (item) => `${item.username ?? 'User'} · ${item.email ?? ''}`, required: true };
  const groupField: Field = { name: 'groupId', label: 'Group', type: 'relation', relationEndpoint: '/access/groups', relationLabel: (item) => item.name ?? 'Group', required: true };
  const episodeField: Field = { name: 'episodeIds', label: 'Episodes', type: 'relation-multi', relationEndpoint: '/episodes', relationLabel: (item) => `Episode ${item.episodeNumber} · ${item.title ?? 'Untitled'}`, required: true };
  const fields: Field[] = tab === 'members' ? [groupField, userField, { name: 'startsAt', label: 'Starts at', required: true, placeholder: '2026-07-17T00:00:00Z' }, { name: 'endsAt', label: 'Ends at', required: true, placeholder: '2026-08-17T00:00:00Z' }, { name: 'comment', label: 'Internal note', type: 'textarea' }, { name: 'subscription', label: 'Subscription member', type: 'checkbox' }] : tab === 'direct' ? [userField, episodeField, { name: 'startsAt', label: 'Starts at', required: true, placeholder: '2026-07-17T00:00:00Z' }, { name: 'endsAt', label: 'Ends at', required: true, placeholder: '2026-08-17T00:00:00Z' }, { name: 'note', label: 'Grant note', type: 'textarea' }] : [groupField, episodeField, { name: 'startsAt', label: 'Starts at', required: true, placeholder: '2026-07-17T00:00:00Z' }, { name: 'endsAt', label: 'Ends at', required: true, placeholder: '2026-08-17T00:00:00Z' }, { name: 'note', label: 'Grant note', type: 'textarea' }];
  return <div><PageHeader eyebrow="Access control" title="Groups & access" description="Create subscriber groups, manage members, and grant episodes directly or through groups without exposing media URLs." actions={<div className="flex flex-wrap gap-1 border border-line bg-white p-1">{(['groups', 'members', 'access', 'direct'] as const).map((item) => <button key={item} onClick={() => setTab(item)} className={`px-3 py-2 text-xs font-semibold capitalize ${tab === item ? 'bg-ink text-white' : 'text-slate-500'}`}>{item === 'access' ? 'Group grants' : item === 'direct' ? 'Direct grants' : item}</button>)}</div>} />{tab === 'groups' ? <ResourceWorkspace section="groups" resource={resources.groups} /> : <><FormPanel title={tab === 'members' ? 'Add or renew a group member' : tab === 'direct' ? 'Grant episodes to a user' : 'Grant episodes to a group'} fields={fields} initialValues={tab === 'members' ? { subscription: true } : undefined} onCancel={() => setValues({})} onSubmit={(payload) => { setValues(payload); mutation.mutate(payload); }} submitting={mutation.isPending} />{notice && <Toast message={notice} kind={notice.includes('updated') || notice.includes('granted') ? 'success' : 'error'} />}{tab === 'members' && values.groupId && <section className="surface mt-5 overflow-x-auto p-5"><div className="mb-4 font-semibold">Current group members</div>{membersQuery.isLoading ? <LoadingState /> : <table className="w-full min-w-[600px] text-left text-sm"><thead><tr>{['User', 'Window', 'Status', 'Action'].map((head) => <th key={head} className="border-b border-line px-3 py-2 text-xs uppercase text-slate-500">{head}</th>)}</tr></thead><tbody>{(membersQuery.data?.items ?? []).map((member: AnyRecord) => <tr key={member.id}><td className="table-cell">{member.user?.username} <span className="text-xs text-slate-500">{member.user?.email}</span></td><td className="table-cell">{formatDate(member.startsAt)} - {formatDate(member.endsAt)}</td><td className="table-cell"><StatusBadge value={member.revokedAt ? 'REVOKED' : 'ACTIVE'} /></td><td className="table-cell"><button className="btn-quiet h-8 px-2 text-red-600" onClick={() => removeMember.mutate({ groupId: values.groupId, userId: member.userId })}><Trash2 size={14} /> Remove</button></td></tr>)}</tbody></table>}{!membersQuery.isLoading && !(membersQuery.data?.items ?? []).length && <div className="py-5 text-sm text-slate-500">No members found for this group.</div>}</section>}{(tab === 'access' && values.groupId || tab === 'direct' && values.userId) && <GrantList groupId={tab === 'access' ? values.groupId : undefined} userId={tab === 'direct' ? values.userId : undefined} />}<div className="surface mt-5 p-5 text-sm leading-6 text-slate-500">Dates are submitted as ISO timestamps. Bulk grants are limited to 500 IDs per request and every grant is recorded in backend history.</div></>}</div>;
}

function GrantList({ groupId, userId }: { groupId?: string; userId?: string }) { const query = useQuery({ queryKey: ['access-grants', groupId, userId], queryFn: async () => (await api.get('/access/grants', { params: { groupId, userId, page: 1, limit: 50 } })).data }); const revoke = useMutation({ mutationFn: (id: string) => api.delete(`/access/grants/${id}`), onSuccess: () => query.refetch() }); if (query.isLoading) return <LoadingState label="Loading access grants" />; const rows = query.data?.items ?? []; return <section className="surface mt-5 overflow-x-auto p-5"><div className="mb-4 font-semibold">Current episode grants</div>{rows.length ? <table className="w-full min-w-[700px] text-left text-sm"><thead><tr>{['Episode', 'User / group', 'Window', 'Status', 'Action'].map((head) => <th key={head} className="border-b border-line px-3 py-2 text-xs uppercase text-slate-500">{head}</th>)}</tr></thead><tbody>{rows.map((row: AnyRecord) => <tr key={row.id}><td className="table-cell">{row.episode?.title ?? row.episode?.id}</td><td className="table-cell">{row.user?.username ?? row.group?.name ?? 'Direct access'}</td><td className="table-cell">{formatDate(row.startsAt)} - {formatDate(row.endsAt)}</td><td className="table-cell"><StatusBadge value={row.status} /></td><td className="table-cell"><button className="btn-quiet h-8 px-2 text-red-600" disabled={revoke.isPending} onClick={() => { if (window.confirm('Revoke this grant?')) revoke.mutate(row.id); }}><Trash2 size={14} /> Revoke</button></td></tr>)}</tbody></table> : <div className="py-5 text-sm text-slate-500">No grants found.</div>}</section>; }

type ContentKind = 'dramas' | 'seasons' | 'episodes';

function ContentWorkspace() {
  return <ContentCatalog />;
}

function HierarchyFormPanel({ kind, editing, dramas, dramasLoading, fields, onCancel, onSubmit, submitting }: { kind: ContentKind; editing: AnyRecord | null; dramas: AnyRecord[]; dramasLoading: boolean; fields: Field[]; onCancel: () => void; onSubmit: (payload: AnyRecord) => void; submitting: boolean }) {
  const initialDramaId = kind === 'seasons' ? editing?.dramaId ?? editing?.drama?.id ?? '' : kind === 'episodes' ? editing?.season?.drama?.id ?? '' : '';
  const [values, setValues] = useState<AnyRecord>(() => ({ ...editing, dramaId: initialDramaId, seasonId: kind === 'episodes' ? editing?.seasonId ?? '' : undefined }));
  const [formError, setFormError] = useState('');
  const seasonsQuery = useQuery<PageResult<AnyRecord>>({ queryKey: ['content-season-options', values.dramaId], queryFn: async () => (await api.get('/seasons', { params: { page: 1, limit: 100, dramaId: values.dramaId } })).data, enabled: kind === 'episodes' && Boolean(values.dramaId) });
  const seasons = seasonsQuery.data?.items ?? [];
  function change(name: string, value: string | boolean | number) { setValues((current) => ({ ...current, [name]: value, ...(name === 'dramaId' && kind === 'episodes' ? { seasonId: '' } : {}) })); }
  function submit() {
    const requiredParent = kind === 'seasons' ? !values.dramaId : kind === 'episodes' ? !values.seasonId : false;
    const missing = fields.find((field) => field.required && (values[field.name] === undefined || values[field.name] === null || String(values[field.name]).trim() === ''));
    if (requiredParent || missing) { setFormError(requiredParent ? kind === 'seasons' ? 'Choose a drama first.' : 'Choose a season first.' : `${missing?.label} is required.`); return; }
    setFormError('');
    const allowedFields = kind === 'seasons' ? ['dramaId', ...fields.map((field) => field.name)] : kind === 'episodes' ? ['seasonId', ...fields.map((field) => field.name)] : fields.map((field) => field.name);
    const payload = Object.fromEntries(allowedFields.map((name) => [name, values[name]]));
    onSubmit(payload);
  }
  return <section className="surface mb-6 p-6"><div className="flex items-center justify-between"><div><div className="eyebrow">Secure form</div><h3 className="mt-1 text-lg font-bold">{editing ? 'Edit' : 'Add'} {kind === 'dramas' ? 'drama' : kind === 'seasons' ? 'season' : 'episode'}</h3><p className="mt-1 text-sm text-slate-500">{kind === 'dramas' ? 'Start with the drama details.' : kind === 'seasons' ? 'Choose the drama that owns this season.' : 'Choose the drama, then choose one of its seasons.'}</p></div><button className="btn-quiet h-8 w-8 p-0" onClick={onCancel} aria-label="Close form"><X size={16} /></button></div><div className="mt-5 grid gap-4 md:grid-cols-2">{kind !== 'dramas' && <label><span className="mb-2 block text-sm font-semibold">Drama <span className="text-brand">*</span></span><select className="select" value={values.dramaId ?? ''} disabled={dramasLoading} onChange={(event) => change('dramaId', event.target.value)}><option value="">{dramasLoading ? 'Loading dramas...' : 'Select a drama'}</option>{dramas.map((drama) => <option key={drama.id} value={drama.id}>{drama.name}</option>)}</select></label>}{kind === 'episodes' && <label><span className="mb-2 block text-sm font-semibold">Season <span className="text-brand">*</span></span><select className="select" value={values.seasonId ?? ''} disabled={!values.dramaId || seasonsQuery.isLoading} onChange={(event) => change('seasonId', event.target.value)}><option value="">{!values.dramaId ? 'Select a drama first' : seasonsQuery.isLoading ? 'Loading seasons...' : 'Select a season'}</option>{seasons.map((season) => <option key={season.id} value={season.id}>Season {season.seasonNumber}{season.title ? ` - ${season.title}` : ''}</option>)}</select></label>}{fields.map((field) => <label key={field.name} className={field.type === 'textarea' ? 'md:col-span-2' : ''}><span className="mb-2 block text-sm font-semibold">{field.label}{field.required && <span className="text-brand"> *</span>}</span>{field.type === 'textarea' ? <textarea className="input min-h-28 py-2" value={values[field.name] ?? ''} onChange={(event) => change(field.name, event.target.value)} placeholder={field.placeholder} /> : field.type === 'select' ? <select className="select" value={values[field.name] ?? ''} onChange={(event) => change(field.name, event.target.value)}><option value="">Select one</option>{field.options?.map((option) => <option key={option} value={option}>{option}</option>)}</select> : field.type === 'checkbox' ? <div className="flex h-10 items-center gap-2"><input type="checkbox" checked={Boolean(values[field.name])} onChange={(event) => change(field.name, event.target.checked)} className="h-4 w-4 accent-teal" /><span className="text-sm text-slate-500">Enabled</span></div> : <input className="input" type={field.type ?? 'text'} value={values[field.name] ?? ''} onChange={(event) => change(field.name, field.type === 'number' ? (event.target.value === '' ? '' : Number(event.target.value)) : event.target.value)} placeholder={field.placeholder} />}</label>)}</div>{formError && <div className="mt-4 border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">{formError}</div>}<div className="mt-6 flex justify-end gap-2"><button className="btn-secondary" onClick={onCancel}>Cancel</button><button className="btn-primary" disabled={submitting} onClick={submit}><Check size={15} />{submitting ? 'Saving...' : 'Save record'}</button></div></section>;
}

function SubscriptionsWorkspace() { const [tab, setTab] = useState<'requests' | 'plans' | 'settings'>('requests'); return <div><PageHeader eyebrow="Revenue operations" title="Subscriptions" description="Review manual payment requests, maintain plans, and apply dated access without leaving the panel." actions={<div className="flex gap-1 border border-line bg-white p-1">{(['requests', 'plans', 'settings'] as const).map((item) => <button key={item} onClick={() => setTab(item)} className={`px-3 py-2 text-xs font-semibold capitalize ${tab === item ? 'bg-ink text-white' : 'text-slate-500'}`}>{item}</button>)}</div>} />{tab === 'requests' ? <ResourceWorkspace section="subscription-requests" resource={{ endpoint: '/subscription/requests', fields: [], columns: () => [{ accessorKey: 'id', header: 'Request', cell: ({ row }) => <span className="font-mono text-xs">{row.original.id.slice(0, 8)}</span> }, { accessorKey: 'userId', header: 'User', cell: ({ row }) => <span className="font-mono text-xs">{row.original.userId}</span> }, { accessorKey: 'amountPkr', header: 'Amount', cell: ({ row }) => `PKR ${formatNumber(row.original.amountPkr)}` }, { accessorKey: 'paymentMethod', header: 'Method' }, { accessorKey: 'status', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.status} /> }, { accessorKey: 'createdAt', header: 'Submitted', cell: ({ row }) => formatDate(row.original.createdAt) }, { id: 'actions', header: '', cell: ({ row }) => <SubscriptionActions id={row.original.id} /> }] }} /> : tab === 'plans' ? <ResourceWorkspace section="plans" resource={{ endpoint: '/subscriptions/plans', fields: [{ name: 'name', label: 'Plan name', required: true }, { name: 'pricePkr', label: 'Price (PKR)', type: 'number', required: true }, { name: 'durationDays', label: 'Duration days', type: 'number', required: true }], columns: () => [{ accessorKey: 'name', header: 'Plan' }, { accessorKey: 'pricePkr', header: 'Price' }, { accessorKey: 'durationDays', header: 'Duration' }, { accessorKey: 'isActive', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.isActive} /> }] }} /> : <SettingsWorkspace onlySubscription />}</div>; }
function SubscriptionActions({ id }: { id: string }) { const client = useQueryClient(); const mutation = useMutation({ mutationFn: (status: 'approved' | 'rejected') => api.patch(`/subscription/requests/${id}`, { status }), onSuccess: () => void client.invalidateQueries({ queryKey: ['subscription-requests'] }) }); return <div className="flex gap-1"><button className="btn-quiet h-8 px-2 text-teal" onClick={() => mutation.mutate('approved')}><Check size={14} /> Approve</button><button className="btn-quiet h-8 px-2 text-red-600" onClick={() => mutation.mutate('rejected')}><X size={14} /> Reject</button></div>; }

function SettingsWorkspace({ onlySubscription = false }: { onlySubscription?: boolean }) { const [kind, setKind] = useState<'subscription' | 'remote'>(onlySubscription ? 'subscription' : 'remote'); const query = useQuery({ queryKey: ['settings', kind], queryFn: async () => (await api.get(kind === 'subscription' ? '/subscription/settings' : '/admin/remote-config')).data }); const [values, setValues] = useState<AnyRecord>({}); const mutation = useMutation({ mutationFn: () => kind === 'remote' ? api.put('/admin/remote-config', { configKey: values.configKey, value: values.value, isActive: true }) : api.patch('/subscription/settings', values), onSuccess: () => query.refetch() }); if (query.isLoading) return <LoadingState />; const data = query.data ?? {}; const remoteRows = Array.isArray(data) ? data : []; return <div>{!onlySubscription && <div className="mb-5 flex gap-1 border-b border-line">{(['remote', 'subscription'] as const).map((item) => <button key={item} onClick={() => setKind(item)} className={`border-b-2 px-4 py-3 text-sm font-semibold capitalize ${kind === item ? 'border-brand text-brand' : 'border-transparent text-slate-500'}`}>{item === 'remote' ? 'Remote config' : 'Subscription settings'}</button>)}</div>}<div className="grid gap-6 xl:grid-cols-[1fr_0.8fr]"><section className="surface p-6"><div className="eyebrow">Configuration</div><h3 className="mt-2 text-lg font-bold">{kind === 'remote' ? 'Create or update a mobile flag' : 'Payment instructions'}</h3><div className="mt-5 space-y-4">{kind === 'remote' ? <><label className="block"><span className="mb-2 block text-sm font-semibold">Config key</span><input className="input" value={values.configKey ?? ''} onChange={(e) => setValues({ ...values, configKey: e.target.value })} placeholder="maintenance_mode" /></label><label className="block"><span className="mb-2 block text-sm font-semibold">Value</span><textarea className="input min-h-28 py-2" value={values.value ?? ''} onChange={(e) => setValues({ ...values, value: e.target.value })} placeholder="false" /></label></> : <><label className="block"><span className="mb-2 block text-sm font-semibold">Monthly amount (PKR)</span><input className="input" type="number" value={values.monthlyAmountPkr ?? data.monthlyAmountPkr ?? 1000} onChange={(e) => setValues({ ...values, monthlyAmountPkr: Number(e.target.value) })} /></label><label className="block"><span className="mb-2 block text-sm font-semibold">Payment instructions</span><textarea className="input min-h-28 py-2" value={values.paymentInstructions ?? data.paymentInstructions ?? ''} onChange={(e) => setValues({ ...values, paymentInstructions: e.target.value })} /></label></>}<button className="btn-primary" onClick={() => mutation.mutate()} disabled={mutation.isPending}><Check size={16} /> Save changes</button></div></section><section className="surface p-6"><div className="eyebrow">Current values</div><div className="mt-4 divide-y divide-line">{kind === 'remote' ? remoteRows.map((row: AnyRecord) => <div className="flex items-center justify-between gap-3 py-3" key={row.id}><div><div className="font-mono text-sm">{row.configKey}</div><div className="text-xs text-slate-500">{JSON.stringify(row.value)}</div></div><StatusBadge value={row.isActive} /></div>) : <div className="space-y-3 text-sm"><div className="flex justify-between"><span className="text-slate-500">Monthly amount</span><strong>PKR {formatNumber(data.monthlyAmountPkr)}</strong></div><div className="flex justify-between"><span className="text-slate-500">Currency</span><strong>{data.currency}</strong></div><p className="border-l-2 border-gold pl-3 text-slate-500">{data.paymentInstructions || 'No payment instructions configured.'}</p></div>}</div></section></div></div>; }

function TrendingWorkspace() { return <ResourceWorkspace section="trending" resource={{ endpoint: '/trending', listEndpoint: '/admin/trending', fields: [{ name: 'dramaId', label: 'Drama', type: 'relation', relationEndpoint: '/dramas', relationLabel: (item) => item.name ?? 'Drama', required: true }, { name: 'position', label: 'Position', type: 'number', required: true }], columns: () => [{ accessorKey: 'position', header: 'Position' }, { accessorKey: 'drama', header: 'Drama', cell: ({ row }) => row.original.drama?.name ?? row.original.dramaId }, { accessorKey: 'createdAt', header: 'Added', cell: ({ row }) => formatDate(row.original.createdAt) }] }} />; }
function AnalyticsWorkspace() { const query = useQuery({ queryKey: ['analytics'], queryFn: async () => (await api.get('/analytics/views', { params: { page: 1, limit: 25 } })).data }); if (query.isLoading) return <LoadingState />; if (query.isError) return <ErrorState message={apiError(query.error)} onRetry={() => query.refetch()} />; const data = query.data ?? {}; return <div><PageHeader eyebrow="Signal" title="Analytics & reports" description="View activity from the same view and reporting workflows used by the legacy panel." /><div className="mb-6 grid gap-4 sm:grid-cols-3"><StatCard label="Views in result" value={formatNumber(data.total)} note={`${formatNumber(data.uniqueUsers)} unique users`} icon={BarChart3} tone="teal" /><StatCard label="Current page" value={formatNumber(data.page)} note="Paginated view activity" icon={ActivityIcon} tone="brand" /><StatCard label="Rows shown" value={formatNumber(data.items?.length)} note="Latest activity first" icon={RefreshCw} tone="gold" /></div><div className="surface overflow-x-auto"><table className="w-full min-w-[720px] text-left"><thead className="bg-slate-50"><tr>{['Episode', 'User', 'Viewed at'].map((head) => <th className="border-b border-line px-4 py-3 text-[11px] font-bold uppercase tracking-[0.12em] text-slate-500" key={head}>{head}</th>)}</tr></thead><tbody>{data.items?.map((item: AnyRecord) => <tr key={item.id}><td className="table-cell font-semibold">{item.episode?.title ?? item.episodeId}</td><td className="table-cell">{item.user?.username ?? item.userId}</td><td className="table-cell">{formatDate(item.viewedAt)}</td></tr>)}</tbody></table></div></div>; }
function ActivityIcon(props: { size?: number }) { return <Activity {...props} />; }
function CommentsWorkspace() { const [episodeId, setEpisodeId] = useState(''); const query = useQuery({ queryKey: ['comments', episodeId], queryFn: async () => (await api.get(`/episodes/${episodeId}/comments`, { params: { page: 1, limit: 25 } })).data, enabled: episodeId.length > 10 }); const mutation = useMutation({ mutationFn: ({ id, status }: { id: string; status: string }) => api.patch(`/comments/${id}`, { status }), onSuccess: () => query.refetch() }); const remove = useMutation({ mutationFn: (id: string) => api.delete(`/comments/${id}`), onSuccess: () => query.refetch() }); return <div><PageHeader eyebrow="Community" title="Comments" description="Choose an episode to inspect, hide, restore, or delete comments." /><div className="mb-5 flex max-w-2xl items-end gap-2"><div className="flex-1"><RelationshipSelect field={{ name: 'episodeId', label: 'Episode', type: 'relation', relationEndpoint: '/episodes', relationLabel: (item) => `Episode ${item.episodeNumber} · ${item.title ?? 'Untitled'}` }} value={episodeId} onChange={setEpisodeId} /></div><button className="btn-secondary" onClick={() => query.refetch()} disabled={!episodeId}><Search size={16} /> Load</button></div>{query.isFetching ? <LoadingState /> : query.data?.items?.length ? <div className="surface divide-y divide-line">{query.data.items.map((item: AnyRecord) => <div className="flex items-start gap-4 p-5" key={item.id}><div className="flex h-9 w-9 shrink-0 items-center justify-center bg-teal/10 text-xs font-bold text-teal">{item.user?.username?.slice(0, 2).toUpperCase() ?? 'U'}</div><div className="flex-1"><div className="flex justify-between gap-3"><strong>{item.user?.username ?? 'User'}</strong><span className="text-xs text-slate-500">{formatDate(item.createdAt)}</span></div><p className="mt-2 text-sm text-slate-600">{item.body}</p><StatusBadge value={item.status} /></div><div className="flex gap-1"><button className="btn-quiet h-8 px-2 text-red-600" disabled={mutation.isPending} onClick={() => mutation.mutate({ id: item.id, status: 'hidden' })}><Trash2 size={14} /> Hide</button>{item.status === 'hidden' && <button className="btn-quiet h-8 px-2 text-teal" disabled={mutation.isPending} onClick={() => mutation.mutate({ id: item.id, status: 'visible' })}><Check size={14} /> Restore</button>}<button className="btn-quiet h-8 px-2 text-red-600" disabled={remove.isPending} onClick={() => { if (window.confirm('Delete this comment?')) remove.mutate(item.id); }}><Trash2 size={14} /> Delete</button></div></div>)}</div> : <div className="surface p-10 text-center text-sm text-slate-500">Load an episode to review comments.</div>}</div>; }
function AuditWorkspace() { const query = useQuery({ queryKey: ['audit'], queryFn: async () => (await api.get('/audit', { params: { page: 1, limit: 50 } })).data }); if (query.isLoading) return <LoadingState />; if (query.isError) return <ErrorState message={apiError(query.error)} onRetry={() => query.refetch()} />; const data = query.data ?? {}; return <div><PageHeader eyebrow="Traceability" title="Audit logs" description="A searchable record of sensitive staff and platform actions." /><div className="surface overflow-x-auto"><table className="w-full min-w-[850px] text-left"><thead className="bg-slate-50"><tr>{['Action', 'Resource', 'Outcome', 'Request ID', 'Timestamp'].map((head) => <th key={head} className="border-b border-line px-4 py-3 text-[11px] font-bold uppercase tracking-[0.12em] text-slate-500">{head}</th>)}</tr></thead><tbody>{(data.items ?? []).map((item: AnyRecord) => <tr key={item.id}><td className="table-cell font-semibold">{item.action}</td><td className="table-cell">{item.resource}</td><td className="table-cell"><StatusBadge value={item.outcome} /></td><td className="table-cell font-mono text-xs">{item.requestId}</td><td className="table-cell">{formatDate(item.createdAt)}</td></tr>)}</tbody></table></div></div>; }
function MessagesWorkspace() { return <ResourceWorkspace section="messages" resource={{ endpoint: '/messages', fields: [{ name: 'userId', label: 'User', type: 'relation', relationEndpoint: '/users', relationLabel: (item) => `${item.username ?? 'User'} · ${item.email ?? ''}`, required: true }, { name: 'message', label: 'Message', type: 'textarea', required: true }], columns: () => [{ accessorKey: 'message', header: 'Message' }, { accessorKey: 'user', header: 'Customer', cell: ({ row }) => row.original.user?.username ?? row.original.userId ?? 'Unknown' }, { accessorKey: 'sender', header: 'From', cell: ({ row }) => row.original.sender?.username ?? 'System' }, { accessorKey: 'status', header: 'Status', cell: ({ row }) => <StatusBadge value={row.original.status} /> }, { accessorKey: 'createdAt', header: 'Sent', cell: ({ row }) => formatDate(row.original.createdAt) }] }} />; }

function UploadsWorkspace() {
  const [file, setFile] = useState<File | null>(null);
  const [purpose, setPurpose] = useState('episode_video');
  const [targetId, setTargetId] = useState('');
  const [versionName, setVersionName] = useState('');
  const [versionCode, setVersionCode] = useState('');
  const [notificationTitle, setNotificationTitle] = useState('');
  const [notificationMessage, setNotificationMessage] = useState('');
  const [progress, setProgress] = useState(0);
  const [notice, setNotice] = useState('');
  const [busy, setBusy] = useState(false);
  async function upload() {
    if (!file) { setNotice('Choose a file first.'); return; }
    setBusy(true); setNotice(''); setProgress(0);
    try {
      const chunkSize = 8 * 1024 * 1024;
      const totalChunks = Math.ceil(file.size / chunkSize);
      const init = await api.post('/uploads/init', { purpose, targetId: targetId || undefined, originalName: file.name, mimeType: file.type || 'application/octet-stream', sizeBytes: file.size, totalChunks });
      const uploadId = init.data.uploadId as string;
      for (let index = 0; index < totalChunks; index += 1) {
        const body = new FormData();
        body.append('chunk', file.slice(index * chunkSize, Math.min(file.size, (index + 1) * chunkSize)), file.name);
        body.append('chunkIndex', String(index));
        await api.post(`/uploads/${uploadId}/chunks`, body, { headers: { 'Content-Type': 'multipart/form-data' }, onUploadProgress: (event) => { const chunkProgress = event.total ? event.loaded / event.total : 0; setProgress(Math.round(((index + chunkProgress) / totalChunks) * 100)); } });
      }
      const result = await api.post(`/uploads/${uploadId}/complete`, { targetId: targetId || undefined });
      let completionMessage = `Upload complete. Staged key: ${result.data.storageKey ?? result.data.uploadId}`;
      if (purpose === 'episode_video' && targetId && result.data.encryptedLocator) {
        const mediaType = file.type.includes('mpegurl') || file.name.toLowerCase().endsWith('.m3u8') ? 'HLS' : file.type.includes('dash') ? 'DASH' : file.type.includes('mp4') ? 'MP4' : 'OTHER';
        await api.post('/media-assets', { episodeId: targetId, mediaType, provider: 'storage', encryptedLocator: result.data.encryptedLocator, status: 'ACTIVE' });
        completionMessage = 'Upload complete and the secure media asset was attached to the episode.';
      } else if (result.data.storageKey && !String(result.data.storageKey).startsWith('staged:')) {
        if (purpose === 'banner') {
          await api.post('/banners', file.type.startsWith('video/') ? { videoKey: result.data.storageKey, isActive: false } : { imageKey: result.data.storageKey, isActive: false });
          completionMessage = 'Upload complete and the banner record was created.';
        } else if (purpose === 'notification_image' && notificationTitle.trim() && notificationMessage.trim()) {
          await api.post('/notifications', { title: notificationTitle.trim(), message: notificationMessage.trim(), imageKey: result.data.storageKey });
          completionMessage = 'Upload complete and the notification record was created.';
        } else if (purpose === 'apk' && versionName.trim() && Number(versionCode) > 0) {
          await api.post('/app/releases', { versionName: versionName.trim(), versionCode: Number(versionCode), storageKey: result.data.storageKey, originalName: file.name, fileSize: file.size, isActive: false });
          completionMessage = 'Upload complete and the APK release record was created.';
        }
      }
      setProgress(100); setNotice(completionMessage); setFile(null);
    } catch (error) { setNotice(apiError(error)); }
    finally { setBusy(false); }
  }
  return <div><PageHeader eyebrow="Storage operations" title="Uploads" description="Upload episode media, thumbnails, notification images, and APK files through resumable server-owned chunks." /><section className="surface max-w-3xl p-6"><div className="grid gap-4 md:grid-cols-2"><label><span className="mb-2 block text-sm font-semibold">Purpose</span><select className="select" value={purpose} onChange={(event) => setPurpose(event.target.value)}><option value="episode_video">Episode video</option><option value="thumbnail">Thumbnail</option><option value="notification_image">Notification image</option><option value="banner">Banner media</option><option value="apk">APK release</option></select></label><label><span className="mb-2 block text-sm font-semibold">Target record</span>{purpose === 'episode_video' || purpose === 'thumbnail' ? <RelationshipSelect field={{ name: 'targetId', label: 'Episode', type: 'relation', relationEndpoint: '/episodes', relationLabel: (item) => `Episode ${item.episodeNumber} · ${item.title ?? 'Untitled'}` }} value={targetId} onChange={setTargetId} /> : <input className="input" value={targetId} onChange={(event) => setTargetId(event.target.value)} placeholder="Optional record reference" />}</label></div>{purpose === 'apk' && <div className="mt-4 grid gap-4 md:grid-cols-2"><label><span className="mb-2 block text-sm font-semibold">Version name</span><input className="input" value={versionName} onChange={(event) => setVersionName(event.target.value)} placeholder="1.0.0" /></label><label><span className="mb-2 block text-sm font-semibold">Version code</span><input className="input" type="number" min="1" value={versionCode} onChange={(event) => setVersionCode(event.target.value)} placeholder="100" /></label></div>}{purpose === 'notification_image' && <div className="mt-4 grid gap-4 md:grid-cols-2"><label><span className="mb-2 block text-sm font-semibold">Notification title</span><input className="input" value={notificationTitle} onChange={(event) => setNotificationTitle(event.target.value)} /></label><label><span className="mb-2 block text-sm font-semibold">Notification message</span><input className="input" value={notificationMessage} onChange={(event) => setNotificationMessage(event.target.value)} /></label></div>}<label className="mt-5 block"><span className="mb-2 block text-sm font-semibold">File</span><input className="input h-auto py-2" type="file" accept="video/*,image/*,.apk,.m3u8" onChange={(event) => setFile(event.target.files?.[0] ?? null)} /></label>{file && <div className="mt-4 flex items-center gap-3 border border-line bg-slate-50 p-3 text-sm"><UploadCloud size={18} className="text-teal" /><div className="min-w-0 flex-1"><div className="truncate font-semibold">{file.name}</div><div className="text-xs text-slate-500">{formatNumber(file.size / 1024 / 1024)} MB</div></div><StatusBadge value={purpose} /></div>}{busy || progress ? <div className="mt-5"><div className="mb-2 flex justify-between text-xs font-semibold"><span>Secure chunk upload</span><span>{progress}%</span></div><div className="h-2 bg-slate-100"><div className="h-2 bg-teal transition-all" style={{ width: `${progress}%` }} /></div></div> : null}{notice && <div className={`mt-4 border px-3 py-2 text-sm ${notice.includes('complete') ? 'border-teal/30 bg-teal/5 text-teal' : 'border-red-200 bg-red-50 text-red-700'}`}>{notice}</div>}<div className="mt-6 flex justify-end"><button className="btn-primary" disabled={busy || !file} onClick={() => void upload()}><UploadCloud size={16} />{busy ? 'Uploading...' : 'Start upload'}</button></div></section></div>;
}

function FirebaseWorkspace() {
  const status = useQuery({ queryKey: ['firebase-status'], queryFn: async () => (await api.get('/admin/firebase/status')).data });
  const [values, setValues] = useState({ userId: '', title: 'Urdu Bolo test notification', message: 'Firebase delivery is working.' });
  const [notice, setNotice] = useState('');
  const mutation = useMutation({ mutationFn: () => api.post('/admin/firebase/test', values), onSuccess: (response) => setNotice(`Test result: ${response.data.sent} notification(s) sent.`), onError: (error) => setNotice(apiError(error)) });
  if (status.isLoading) return <LoadingState />;
  if (status.isError) return <ErrorState message={apiError(status.error)} onRetry={() => status.refetch()} />;
  return <div><PageHeader eyebrow="Messaging infrastructure" title="Firebase delivery" description="Verify server-side Firebase configuration and send a targeted test without accepting raw device tokens in the browser." actions={<button className="btn-secondary" onClick={() => status.refetch()}><RefreshCw size={16} /> Refresh</button>} /><div className="grid gap-6 xl:grid-cols-[0.8fr_1.2fr]"><section className="surface p-6"><div className="eyebrow">Configuration</div><div className="mt-4 flex items-center gap-3"><div className={`flex h-10 w-10 items-center justify-center ${status.data.configured ? 'bg-teal/10 text-teal' : 'bg-gold/15 text-gold'}`}><ShieldCheck size={20} /></div><div><div className="font-bold">{status.data.configured ? 'Configured' : 'Not configured'}</div><div className="text-sm text-slate-500">{status.data.projectId ?? 'Set FIREBASE_SERVICE_ACCOUNT_B64 on the API'}</div></div></div><div className="mt-6 border-t border-line pt-4 text-sm text-slate-500">Delivery is performed by the NestJS server. Firebase credentials never enter this panel.</div></section><section className="surface p-6"><div className="eyebrow">Controlled test</div><h3 className="mt-2 text-lg font-bold">Send to one registered user</h3><div className="mt-5 grid gap-4 md:grid-cols-2"><label><span className="mb-2 block text-sm font-semibold">User</span><RelationshipSelect field={{ name: 'userId', label: 'User', type: 'relation', relationEndpoint: '/users', relationLabel: (item) => `${item.username ?? 'User'} · ${item.email ?? ''}` }} value={values.userId} onChange={(userId) => setValues({ ...values, userId })} /></label><label><span className="mb-2 block text-sm font-semibold">Title</span><input className="input" value={values.title} onChange={(event) => setValues({ ...values, title: event.target.value })} /></label></div><label className="mt-4 block"><span className="mb-2 block text-sm font-semibold">Message</span><textarea className="input min-h-24 py-2" value={values.message} onChange={(event) => setValues({ ...values, message: event.target.value })} /></label>{notice && <div className="mt-4 border border-line bg-slate-50 px-3 py-2 text-sm">{notice}</div>}<div className="mt-5 flex justify-end"><button className="btn-primary" disabled={mutation.isPending || !values.userId} onClick={() => mutation.mutate()}><Send size={16} />{mutation.isPending ? 'Sending...' : 'Send test'}</button></div></section></div></div>;
}

function WidevineWorkspace() {
  const query = useQuery({ queryKey: ['drm-status'], queryFn: async () => (await api.get('/admin/drm/status')).data });
  const [licenseUrl, setLicenseUrl] = useState('');
  const [result, setResult] = useState<AnyRecord | null>(null);
  const mutation = useMutation({ mutationFn: () => api.post('/admin/drm/validate', licenseUrl ? { licenseUrl } : {}), onSuccess: (response) => setResult(response.data), onError: (error) => setResult({ valid: false, reason: apiError(error) }) });
  if (query.isLoading) return <LoadingState />;
  if (query.isError) return <ErrorState message={apiError(query.error)} onRetry={() => query.refetch()} />;
  return <div><PageHeader eyebrow="Protected playback" title="Widevine / DRM" description="Review the configured license provider and validate HTTPS endpoints. License secrets are never stored in the panel." /><div className="grid gap-6 xl:grid-cols-[0.75fr_1.25fr]"><section className="surface p-6"><div className="eyebrow">Runtime status</div><div className="mt-4 flex items-center gap-3"><StatusBadge value={query.data.configured ? 'Configured' : 'Not configured'} /><span className="text-sm text-slate-500">{query.data.provider}</span></div><dl className="mt-6 space-y-3 text-sm"><div className="flex justify-between gap-4"><dt className="text-slate-500">License host</dt><dd className="font-mono">{query.data.licenseHost ?? 'Not set'}</dd></div><div className="flex justify-between gap-4"><dt className="text-slate-500">Protocol</dt><dd>{query.data.protocol ?? 'Not set'}</dd></div></dl></section><section className="surface p-6"><div className="eyebrow">Endpoint validation</div><label className="mt-5 block"><span className="mb-2 block text-sm font-semibold">Optional license URL override</span><input className="input" value={licenseUrl} onChange={(event) => setLicenseUrl(event.target.value)} placeholder="https://license.example.test/widevine" /></label>{result && <div className={`mt-4 border px-3 py-2 text-sm ${result.valid ? 'border-teal/30 bg-teal/5 text-teal' : 'border-red-200 bg-red-50 text-red-700'}`}>{result.valid ? `Valid HTTPS endpoint: ${result.host}${result.path}` : result.reason}</div>}<div className="mt-5 flex justify-end"><button className="btn-primary" disabled={mutation.isPending} onClick={() => mutation.mutate()}><ShieldCheck size={16} /> Validate endpoint</button></div></section></div></div>;
}

function MediaValidationWorkspace({ previewOnly }: { previewOnly: boolean }) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<AnyRecord | null>(null);
  const query = useQuery({ queryKey: ['media-validation', search], queryFn: async () => (await api.get('/media-assets', { params: { page: 1, limit: 25, search: search || undefined } })).data });
  const mutation = useMutation({ mutationFn: (id: string) => api.get(`/media-assets/${id}/validate`), onSuccess: (response) => setSelected(response.data), onError: (error) => setSelected({ valid: false, reason: apiError(error) }) });
  if (query.isLoading) return <LoadingState />;
  if (query.isError) return <ErrorState message={apiError(query.error)} onRetry={() => query.refetch()} />;
  const rows = query.data?.items ?? [];
  return <div><PageHeader eyebrow="Media operations" title={previewOnly ? 'Media preview' : 'Media validation'} description={previewOnly ? 'Inspect the secure media record and validate its provider path without revealing a permanent URL.' : 'Check encrypted locators, provider allowlists, and media metadata before publishing an episode.'} /><div className="mb-5 flex max-w-xl gap-2"><input className="input" value={search} onChange={(event) => setSearch(event.target.value)} placeholder="Search provider" /><button className="btn-secondary" onClick={() => query.refetch()}><RefreshCw size={16} /> Refresh</button></div>{selected && <section className="surface mb-5 border-l-4 border-teal p-5"><div className="flex items-center gap-3"><ShieldCheck className={selected.valid ? 'text-teal' : 'text-red-600'} size={20} /><strong>{selected.valid ? 'Validation passed' : 'Validation failed'}</strong><StatusBadge value={selected.status ?? (selected.valid ? 'VALID' : 'ERROR')} /></div><div className="mt-3 grid gap-3 text-sm md:grid-cols-3"><div><span className="text-slate-500">Asset</span><div className="font-mono text-xs">{selected.assetId}</div></div><div><span className="text-slate-500">Provider host</span><div>{selected.host ?? selected.reason ?? 'Unavailable'}</div></div><div><span className="text-slate-500">Media type</span><div>{selected.mediaType ?? 'Unknown'}</div></div></div></section>}<div className="surface overflow-x-auto"><table className="w-full min-w-[760px] text-left"><thead className="bg-slate-50"><tr>{['Episode', 'Provider', 'Type', 'Status', 'Version', 'Actions'].map((head) => <th key={head} className="border-b border-line px-4 py-3 text-[11px] font-bold uppercase tracking-[0.12em] text-slate-500">{head}</th>)}</tr></thead><tbody>{rows.map((row: AnyRecord) => <tr key={row.id}><td className="table-cell font-mono text-xs">{row.episodeId}</td><td className="table-cell">{row.provider}</td><td className="table-cell"><StatusBadge value={row.mediaType} /></td><td className="table-cell"><StatusBadge value={row.status} /></td><td className="table-cell">{row.version}</td><td className="table-cell"><button className="btn-quiet h-8 px-2 text-teal" onClick={() => mutation.mutate(row.id)} disabled={mutation.isPending}><ShieldCheck size={14} /> Validate</button></td></tr>)}</tbody></table>{!rows.length && <div className="p-10 text-center text-sm text-slate-500">No media assets found.</div>}</div></div>;
}

function UtilitiesWorkspace() {
  const [resource, setResource] = useState('users');
  const [file, setFile] = useState<File | null>(null);
  const [notice, setNotice] = useState('');
  const endpoints: Record<string, string> = { users: '/users', dramas: '/dramas', seasons: '/seasons', episodes: '/episodes', 'subscription-requests': '/subscription/requests' };
  async function exportData() {
    try { const response = await api.get(endpoints[resource], { params: { page: 1, limit: 500 } }); const items = response.data.items ?? response.data; const rows = Array.isArray(items) ? items : []; const keys = [...new Set(rows.flatMap((row: AnyRecord) => Object.keys(row).filter((key) => ['passwordHash', 'encryptedLocator'].includes(key) === false)))]; const csv = [keys.join(','), ...rows.map((row: AnyRecord) => keys.map((key) => JSON.stringify(typeof row[key] === 'object' ? JSON.stringify(row[key]) : row[key] ?? '')).join(','))].join('\n'); const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' }); const url = URL.createObjectURL(blob); const anchor = document.createElement('a'); anchor.href = url; anchor.download = `${resource}-export.csv`; anchor.click(); URL.revokeObjectURL(url); setNotice(`Exported ${rows.length} record(s).`); } catch (error) { setNotice(apiError(error)); }
  }
  async function importData() {
    if (!file) { setNotice('Choose a CSV file first.'); return; }
    try { const text = await file.text(); const lines = text.split(/\r?\n/).filter(Boolean); const headers = lines.shift()?.split(',').map((value) => value.trim()) ?? []; let imported = 0; for (const line of lines) { const values = line.match(/("(?:[^"]|"")*"|[^,]*)/g)?.filter((_, index, all) => index < all.length - 1) ?? []; const payload = Object.fromEntries(headers.map((header, index) => [header, (values[index] ?? '').replace(/^"|"$/g, '').replace(/""/g, '"')])); await api.post(endpoints[resource], payload); imported += 1; } setNotice(`Imported ${imported} record(s).`); setFile(null); } catch (error) { setNotice(apiError(error)); }
  }
  return <div><PageHeader eyebrow="Data operations" title="Legacy utilities" description="Export safe operational records and import approved CSV rows through the new NestJS API." /><section className="surface max-w-3xl p-6"><div className="grid gap-4 md:grid-cols-2"><label><span className="mb-2 block text-sm font-semibold">Dataset</span><select className="select" value={resource} onChange={(event) => setResource(event.target.value)}>{Object.keys(endpoints).map((key) => <option key={key} value={key}>{key.replace(/-/g, ' ')}</option>)}</select></label><label><span className="mb-2 block text-sm font-semibold">CSV import file</span><input className="input h-auto py-2" type="file" accept=".csv,text/csv" onChange={(event) => setFile(event.target.files?.[0] ?? null)} /></label></div><div className="mt-5 flex flex-wrap justify-end gap-2"><button className="btn-secondary" onClick={() => void exportData()}><Download size={16} /> Export CSV</button><button className="btn-primary" disabled={!file} onClick={() => void importData()}><FileUp size={16} /> Import CSV</button></div>{notice && <div className="mt-4 border border-line bg-slate-50 px-3 py-2 text-sm">{notice}</div>}<p className="mt-5 border-l-2 border-gold pl-3 text-xs leading-5 text-slate-500">Exports omit password hashes, encrypted media locators, and other server-only secrets. Imports are row-by-row validated by the API.</p></section></div>;
}
